import { useParams, Link } from "react-router-dom";
import { Helmet } from "react-helmet";
import Header from "@/components/Header";
import EnhancedFooter from "@/components/EnhancedFooter";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { MapPin, ArrowRight, Phone } from "lucide-react";
import { servicesData, cities } from "@/data/services";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

const ServiceOverview = () => {
  const { service } = useParams();
  const currentService = servicesData[service || "roof-installation"] || servicesData["roof-installation"];
  const parentService = currentService.parentCategory ? servicesData[currentService.parentCategory] : null;

  // Primary cities for display (exclude legacy duplicates)
  const primaryCities = cities.filter(city => 
    ["toronto", "north-york", "scarborough", "etobicoke", "mississauga", "brampton", 
     "vaughan", "richmond-hill", "markham", "oakville", "burlington", "newmarket", "aurora"].includes(city.id)
  );

  const serviceSchema = {
    "@context": "https://schema.org",
    "@type": "Service",
    "serviceType": currentService.title,
    "provider": {
      "@type": "RoofingContractor",
      "name": "Blue Knight Roofing",
      "telephone": "+1-647-383-8664",
      "address": {
        "@type": "PostalAddress",
        "streetAddress": "141-200 Suntract Rd",
        "addressLocality": "North York",
        "addressRegion": "ON",
        "postalCode": "M9N 2V9",
        "addressCountry": "CA"
      }
    },
    "areaServed": primaryCities.map(city => ({
      "@type": "City",
      "name": city.name
    })),
    "description": currentService.metaDescription
  };

  const faqSchema = currentService.faqs && currentService.faqs.length > 0 ? {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": currentService.faqs.map(faq => ({
      "@type": "Question",
      "name": faq.question,
      "acceptedAnswer": {
        "@type": "Answer",
        "text": faq.answer
      }
    }))
  } : null;

  return (
    <>
      <Helmet>
        <title>{currentService.metaTitle}</title>
        <meta name="description" content={currentService.metaDescription} />
        <meta name="keywords" content={`${currentService.keywords}, ${currentService.lsiKeywords}`} />
        <link rel="canonical" href={`https://blueknightroofing.ca/services/${service}`} />
        <meta property="og:title" content={currentService.metaTitle} />
        <meta property="og:description" content={currentService.metaDescription} />
        <meta property="og:type" content="website" />
        <meta property="og:url" content={`https://blueknightroofing.ca/services/${service}`} />
        <script type="application/ld+json">{JSON.stringify(serviceSchema)}</script>
        {faqSchema && (
          <script type="application/ld+json">{JSON.stringify(faqSchema)}</script>
        )}
      </Helmet>

      <div className="min-h-screen flex flex-col">
        <Header />

        <main className="flex-1">
          {/* Hero Section */}
          <section className="bg-gradient-to-br from-primary-dark via-primary to-primary-dark text-white py-20">
            <div className="container">
              <nav className="mb-8 text-sm text-white/80" aria-label="Breadcrumb">
                <ol className="flex items-center flex-wrap">
                  <li><Link to="/" className="hover:text-white">Home</Link></li>
                  <li><span className="mx-2">/</span></li>
                  <li><Link to="/services" className="hover:text-white">Services</Link></li>
                  {parentService && (
                    <>
                      <li><span className="mx-2">/</span></li>
                      <li><Link to={`/services/${currentService.parentCategory}`} className="hover:text-white">{parentService.title}</Link></li>
                    </>
                  )}
                  <li><span className="mx-2">/</span></li>
                  <li><span className="text-white">{currentService.title}</span></li>
                </ol>
              </nav>

              {currentService.badge && (
                <Badge className="mb-4 bg-destructive text-destructive-foreground">
                  {currentService.badge}
                </Badge>
              )}

              <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold mb-6 text-white">
                {currentService.h1}
              </h1>
              <p className="text-xl mb-4 max-w-3xl text-white">
                {currentService.desc}
              </p>
              <p className="text-lg mb-8 max-w-3xl text-white/90">
                {currentService.longDesc}
              </p>
              <div className="flex flex-wrap gap-4">
                <Button asChild size="lg" variant="secondary" className="rounded-full">
                  <a href="tel:16473838664">
                    <Phone className="w-4 h-4 mr-2" />
                    Call (647) 383-8664
                  </a>
                </Button>
                <Button asChild size="lg" variant="outline" className="rounded-full border-white text-white hover:bg-white/10">
                  <Link to="/contact">Get Free Estimate</Link>
                </Button>
              </div>
            </div>
          </section>

          {/* Sub-Services Section */}
          {currentService.subServices && currentService.subServices.length > 0 && (
            <section className="py-16 bg-muted">
              <div className="container">
                <h2 className="text-3xl md:text-4xl font-bold mb-4 text-center text-foreground">
                  Our {currentService.title} Services
                </h2>
                <p className="text-center text-muted-foreground mb-10 max-w-3xl mx-auto">
                  Explore our specialized services within {currentService.title.toLowerCase()}.
                </p>
                <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {currentService.subServices.map((sub) => (
                    <Link
                      key={sub.id}
                      to={`/services/${sub.id}`}
                      className="group bg-background rounded-xl p-6 shadow-sm border border-border hover:border-primary/40 hover:shadow-lg transition-all"
                    >
                      <h3 className="text-lg font-bold text-primary-dark mb-2 group-hover:text-primary transition-colors">
                        {sub.title}
                      </h3>
                      <p className="text-sm text-muted-foreground mb-4">{sub.description}</p>
                      <span className="inline-flex items-center text-sm font-medium text-primary gap-1">
                        Learn More <ArrowRight className="w-4 h-4" />
                      </span>
                    </Link>
                  ))}
                </div>
              </div>
            </section>
          )}

          {/* Service Features Section */}
          {currentService.features && currentService.features.length > 0 && (
            <section className="py-16 bg-muted">
              <div className="container">
                <div className="text-center mb-12">
                  <h2 className="text-3xl md:text-4xl font-bold mb-4 text-foreground">
                    {currentService.h2Sections[0] || `Our ${currentService.title} Services`}
                  </h2>
                  <p className="text-xl text-muted-foreground max-w-3xl mx-auto">
                    Comprehensive solutions using advanced equipment and proven techniques
                  </p>
                </div>
                <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
                  {currentService.features.map((feature) => {
                    const Icon = feature.icon;
                    return (
                      <div key={feature.title} className="bg-background rounded-xl p-6 hover:shadow-lg transition-shadow">
                        <div className="text-primary mb-4">
                          <Icon className="w-8 h-8" />
                        </div>
                        <h3 className="text-xl font-bold mb-2 text-foreground">{feature.title}</h3>
                        <p className="text-muted-foreground">{feature.description}</p>
                      </div>
                    );
                  })}
                </div>
              </div>
            </section>
          )}

          {/* Service Images Section */}
          {currentService.images && currentService.images.length > 0 && (
            <section className="py-16">
              <div className="container">
                <h2 className="text-3xl md:text-4xl font-bold mb-4 text-center text-foreground">
                  {currentService.h2Sections[1] || `Professional ${currentService.title}`}
                </h2>
                <p className="text-xl text-muted-foreground text-center mb-12 max-w-3xl mx-auto">
                  See our expert work and professional equipment in action
                </p>
                <div className="grid md:grid-cols-3 gap-6">
                  {currentService.images.map((image) => (
                    <div key={image.title} className="group overflow-hidden rounded-xl shadow-lg">
                      <img 
                        src={image.src} 
                        alt={image.alt}
                        className="w-full h-64 object-cover group-hover:scale-105 transition-transform duration-300"
                        loading="lazy"
                      />
                      <div className="p-4 bg-background">
                        <h3 className="font-bold text-foreground">{image.title}</h3>
                        <p className="text-sm text-muted-foreground">{image.description}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </section>
          )}

          {/* Benefits Section */}
          {currentService.benefits && currentService.benefits.length > 0 && (
            <section className="py-16 bg-background">
              <div className="container">
                <h2 className="text-3xl font-bold mb-12 text-center text-primary-dark">
                  {currentService.h2Sections[3] || `Why Choose Our ${currentService.title}`}
                </h2>
                <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
                  {currentService.benefits.map((benefit) => {
                    const Icon = benefit.icon;
                    return (
                      <div key={benefit.title} className="text-center">
                        <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-primary/10 text-primary mb-4">
                          <Icon className="w-6 h-6" />
                        </div>
                        <h3 className="text-xl font-bold mb-2 text-primary-dark">{benefit.title}</h3>
                        <p className="text-muted-foreground">{benefit.desc}</p>
                      </div>
                    );
                  })}
                </div>
              </div>
            </section>
          )}

          {/* Why Choose Us Section */}
          {currentService.whyChooseUs && currentService.whyChooseUs.length > 0 && (
            <section className="py-16 bg-muted">
              <div className="container">
                <h2 className="text-3xl md:text-4xl font-bold mb-12 text-center text-foreground">
                  {currentService.h2Sections[5] || "Why Choose Blue Knight Roofing"}
                </h2>
                <div className="grid md:grid-cols-3 gap-8">
                  {currentService.whyChooseUs.map((item) => {
                    const Icon = item.icon;
                    return (
                      <div key={item.title} className="flex flex-col items-center text-center">
                        <div className="bg-primary text-primary-foreground rounded-full p-4 mb-4">
                          <Icon className="w-8 h-8" />
                        </div>
                        <h3 className="text-xl font-bold mb-2 text-foreground">{item.title}</h3>
                        <p className="text-muted-foreground">{item.description}</p>
                      </div>
                    );
                  })}
                </div>
              </div>
            </section>
          )}

          {/* FAQ Section */}
          {currentService.faqs && currentService.faqs.length > 0 && (
            <section className="py-16">
              <div className="container max-w-4xl">
                <h2 className="text-3xl md:text-4xl font-bold mb-8 text-center text-foreground">
                  Frequently Asked Questions
                </h2>
                <Accordion type="single" collapsible className="w-full">
                  {currentService.faqs.map((faq, index) => (
                    <AccordionItem key={index} value={`item-${index}`}>
                      <AccordionTrigger className="text-left text-foreground">
                        {faq.question}
                      </AccordionTrigger>
                      <AccordionContent className="text-muted-foreground">
                        {faq.answer}
                      </AccordionContent>
                    </AccordionItem>
                  ))}
                </Accordion>
              </div>
            </section>
          )}

          {/* Cities Grid */}
          <section className="py-16 bg-background">
            <div className="container">
              <div className="text-center mb-12">
                <h2 className="text-3xl md:text-4xl font-bold mb-4 text-primary-dark">
                  {currentService.title} Available in These Cities
                </h2>
                <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
                  Select your city to learn more about our local {currentService.title.toLowerCase()} services, pricing, and availability.
                </p>
              </div>

              <div className="grid sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                {primaryCities.map((city) => (
                  <Card 
                    key={city.id}
                    className="p-6 hover:shadow-lg transition-all duration-300 hover:-translate-y-1 bg-card group"
                  >
                    <div className="flex items-start gap-3 mb-4">
                      <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
                        <MapPin className="w-5 h-5 text-primary" />
                      </div>
                      <div className="flex-1">
                        <h3 className="text-lg font-bold text-primary-dark mb-1">
                          {city.name}
                        </h3>
                        <p className="text-sm text-muted-foreground">
                          {city.region}
                        </p>
                      </div>
                    </div>
                    <Button 
                      asChild 
                      variant="default" 
                      className="w-full rounded-full group-hover:shadow-md transition-shadow"
                    >
                      <Link to={`/${service}/${city.id}`} className="flex items-center justify-center gap-2">
                        View {currentService.title}
                        <ArrowRight className="w-4 h-4" />
                      </Link>
                    </Button>
                  </Card>
                ))}
              </div>
            </div>
          </section>

          {/* CTA Section */}
          <section className="py-16 bg-muted/30">
            <div className="container">
              <div className="bg-primary rounded-xl p-8 md:p-12 text-center text-white">
                <h2 className="text-3xl font-bold mb-4 text-white">
                  Ready to Get Started?
                </h2>
                <p className="text-lg mb-8 max-w-2xl mx-auto text-white">
                  Contact Blue Knight Roofing today for expert {currentService.title.toLowerCase()} services. 
                  We serve Toronto and all GTA areas with fast, reliable service and free estimates.
                </p>
                <div className="flex flex-wrap gap-4 justify-center">
                  <Button asChild size="lg" variant="secondary" className="rounded-full">
                    <a href="tel:16473838664">Call Now: (647) 383-8664</a>
                  </Button>
                  <Button asChild size="lg" variant="outline" className="rounded-full border-white text-white hover:bg-white/10">
                    <Link to="/contact">Request Free Quote</Link>
                  </Button>
                </div>
              </div>
            </div>
          </section>
        </main>

        <EnhancedFooter />
      </div>
    </>
  );
};

export default ServiceOverview;